@@ -0,0 +1,390 @@
+---
+import Layout from '../layouts/Layout.astro';
+import showcaseData from '../data/showcase.json';
+
+// Sort by likes (most popular first)
+const sortedShowcase = [...showcaseData].sort((a, b) => b.likes - a.likes);
+
+const categoryLabels: Record<string, string> = {
+  'power-user': '🚀 Power User',
+  'automation': '⚡ Automation',
+  'productivity': '📋 Productivity',
+  'integration': '🔗 Integration',
+  'developer': '💻 Developer',
+  'personal': '👤 Personal',
+  'family': '👨‍👩‍👧 Family',
+  'smart-home': '🏠 Smart Home',
+};
+---
+
+<Layout title="Showcase — What People Are Building with Clawdbot">
+  <div class="stars"></div>
+  <div class="nebula"></div>
+
+  <main class="container">
+    <header class="header">
+      <a href="/" class="back-link">← Back to home</a>
+      <h1 class="title">
+        <span class="claw-accent">⟩</span> What People Are Building
+      </h1>
+      <p class="subtitle">Real projects, real automation, real magic.</p>
+    </header>
+
+    <div class="showcase-grid">
+      {sortedShowcase.map((item) => (
+        <a href={`https://x.com/${item.author}/status/${item.id}`} target="_blank" rel="noopener" class="showcase-card">
+          <div class="card-header">
+            <img
+              src={`https://unavatar.io/x/${item.author}`}
+              alt={item.author}
+              class="avatar"
+              loading="lazy"
+            />
+            <div class="author-info">
+              <span class="author-name">@{item.author}</span>
+              <span class="category-tag">{categoryLabels[item.category] || item.category}</span>
+            </div>
+            <span class="likes">❤️ {item.likes}</span>
+          </div>
+          <p class="quote">{item.quote}</p>
+          {item.images && item.images.length > 0 && (
+            <div class="images">
+              {item.images.map((img: string) => (
+                <img src={img} alt="Screenshot" class="tweet-image" loading="lazy" />
+              ))}
+            </div>
+          )}
+          <span class="view-link">View on X →</span>
+        </a>
+      ))}
+    </div>
+
+    <section class="cta-section">
+      <h2 class="cta-title">Built something cool?</h2>
+      <p class="cta-desc">Share your Clawdbot creation with the community</p>
+      <div class="cta-buttons">
+        <a href="https://twitter.com/intent/tweet?text=Check%20out%20what%20I%20built%20with%20%40clawdbot%21" target="_blank" rel="noopener" class="cta-btn cta-primary">Share on X</a>
+        <a href="https://discord.com/invite/clawd" target="_blank" rel="noopener" class="cta-btn cta-secondary">Join Discord</a>
+      </div>
+    </section>
+
+    <footer class="footer">
+      <nav class="footer-nav">
+        <a href="/">Home</a>
+        <span class="footer-separator">·</span>
+        <a href="/shoutouts">Shoutouts</a>
+        <span class="footer-separator">·</span>
+        <a href="/integrations">Integrations</a>
+      </nav>
+      <p>Built by <a href="https://clawd.me" target="_blank" rel="noopener">Clawd</a> 🦞</p>
+    </footer>
+  </main>
+</Layout>
+
+<style>
+  .stars {
+    position: fixed;
+    inset: 0;
+    background-image:
+      radial-gradient(2px 2px at 20px 30px, rgba(255,255,255,0.8), transparent),
+      radial-gradient(2px 2px at 40px 70px, rgba(255,255,255,0.5), transparent),
+      radial-gradient(1px 1px at 90px 40px, rgba(255,255,255,0.6), transparent),
+      radial-gradient(2px 2px at 130px 80px, rgba(255,255,255,0.4), transparent),
+      radial-gradient(1px 1px at 160px 120px, rgba(255,255,255,0.7), transparent),
+      radial-gradient(2px 2px at 200px 60px, rgba(0,229,204,0.6), transparent),
+      radial-gradient(1px 1px at 250px 150px, rgba(255,255,255,0.5), transparent),
+      radial-gradient(2px 2px at 300px 40px, rgba(255,77,77,0.4), transparent);
+    background-size: 350px 200px;
+    animation: twinkle 8s ease-in-out infinite alternate;
+    pointer-events: none;
+    z-index: 0;
+  }
+
+  @keyframes twinkle {
+    0% { opacity: 0.4; }
+    100% { opacity: 0.7; }
+  }
+
+  .nebula {
+    position: fixed;
+    inset: 0;
+    background:
+      radial-gradient(ellipse 80% 50% at 20% 20%, rgba(255, 77, 77, 0.12), transparent 50%),
+      radial-gradient(ellipse 60% 60% at 80% 30%, rgba(0, 229, 204, 0.08), transparent 50%),
+      radial-gradient(ellipse 90% 70% at 50% 90%, rgba(255, 77, 77, 0.06), transparent 50%);
+    pointer-events: none;
+    z-index: 0;
+  }
+
+  .container {
+    position: relative;
+    z-index: 1;
+    max-width: 1200px;
+    margin: 0 auto;
+    padding: 40px 24px;
+    min-height: 100vh;
+    display: flex;
+    flex-direction: column;
+  }
+
+  .header {
+    text-align: center;
+    margin-bottom: 48px;
+    animation: fadeInUp 0.6s ease-out;
+  }
+
+  @keyframes fadeInUp {
+    from { opacity: 0; transform: translateY(20px); }
+    to { opacity: 1; transform: translateY(0); }
+  }
+
+  .back-link {
+    display: inline-block;
+    margin-bottom: 24px;
+    color: var(--text-muted);
+    text-decoration: none;
+    font-size: 0.9rem;
+    transition: color 0.2s ease;
+  }
+
+  .back-link:hover {
+    color: var(--coral-bright);
+  }
+
+  .title {
+    font-family: var(--font-display);
+    font-size: clamp(2rem, 6vw, 3rem);
+    font-weight: 700;
+    margin-bottom: 12px;
+    color: var(--text-primary);
+  }
+
+  .claw-accent {
+    color: var(--coral-bright);
+  }
+
+  .subtitle {
+    color: var(--text-secondary);
+    font-size: 1.1rem;
+  }
+
+  .showcase-grid {
+    display: grid;
+    grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
+    gap: 20px;
+    margin-bottom: 56px;
+  }
+
+  .showcase-card {
+    display: flex;
+    flex-direction: column;
+    gap: 16px;
+    padding: 24px;
+    border-radius: 16px;
+    border: 1px solid var(--border-subtle);
+    background: rgba(10, 15, 26, 0.7);
+    backdrop-filter: blur(8px);
+    text-decoration: none;
+    color: var(--text-primary);
+    transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
+  }
+
+  .showcase-card:hover {
+    border-color: var(--coral-bright);
+    transform: translateY(-4px);
+    box-shadow: 0 16px 48px rgba(255, 77, 77, 0.15);
+  }
+
+  .card-header {
+    display: flex;
+    align-items: center;
+    gap: 12px;
+  }
+
+  .avatar {
+    width: 48px;
+    height: 48px;
+    border-radius: 50%;
+    flex-shrink: 0;
+    border: 2px solid var(--border-subtle);
+    background: var(--bg-elevated);
+    object-fit: cover;
+  }
+
+  .author-info {
+    display: flex;
+    flex-direction: column;
+    gap: 2px;
+    flex: 1;
+  }
+
+  .author-name {
+    font-weight: 600;
+    color: var(--coral-bright);
+    font-size: 0.95rem;
+  }
+
+  .category-tag {
+    font-size: 0.75rem;
+    color: var(--text-muted);
+  }
+
+  .likes {
+    font-size: 0.85rem;
+    color: var(--text-muted);
+  }
+
+  .quote {
+    font-size: 0.9rem;
+    line-height: 1.6;
+    color: var(--text-secondary);
+    white-space: pre-line;
+  }
+
+  .images {
+    display: grid;
+    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
+    gap: 8px;
+    margin-top: 12px;
+  }
+
+  .tweet-image {
+    width: 100%;
+    height: auto;
+    border-radius: 8px;
+    border: 1px solid var(--border-subtle);
+    object-fit: cover;
+    max-height: 200px;
+  }
+
+  .view-link {
+    font-size: 0.85rem;
+    color: var(--text-muted);
+    padding-top: 12px;
+    border-top: 1px solid var(--border-subtle);
+    transition: color 0.2s ease;
+  }
+
+  .showcase-card:hover .view-link {
+    color: var(--coral-bright);
+  }
+
+  .cta-section {
+    text-align: center;
+    padding: 48px 24px;
+    border-radius: 20px;
+    border: 1px solid var(--border-subtle);
+    background: rgba(10, 15, 26, 0.7);
+    backdrop-filter: blur(12px);
+    margin-bottom: 48px;
+  }
+
+  .cta-title {
+    font-family: var(--font-display);
+    font-size: 1.5rem;
+    font-weight: 600;
+    color: var(--text-primary);
+    margin-bottom: 8px;
+  }
+
+  .cta-desc {
+    color: var(--text-secondary);
+    margin-bottom: 24px;
+  }
+
+  .cta-buttons {
+    display: flex;
+    gap: 16px;
+    justify-content: center;
+    flex-wrap: wrap;
+  }
+
+  .cta-btn {
+    display: inline-flex;
+    align-items: center;
+    gap: 8px;
+    padding: 12px 24px;
+    border-radius: 10px;
+    font-family: var(--font-display);
+    font-weight: 600;
+    font-size: 0.95rem;
+    text-decoration: none;
+    transition: all 0.25s ease;
+  }
+
+  .cta-primary {
+    background: linear-gradient(135deg, var(--coral-bright) 0%, var(--coral-dark) 100%);
+    color: white;
+    box-shadow: 0 4px 20px rgba(255, 77, 77, 0.3);
+  }
+
+  .cta-primary:hover {
+    transform: translateY(-2px);
+    box-shadow: 0 8px 30px rgba(255, 77, 77, 0.4);
+  }
+
+  .cta-secondary {
+    background: rgba(88, 101, 242, 0.15);
+    border: 1px solid #5865F2;
+    color: #5865F2;
+  }
+
+  .cta-secondary:hover {
+    background: rgba(88, 101, 242, 0.25);
+    transform: translateY(-2px);
+  }
+
+  .footer {
+    margin-top: auto;
+    padding-top: 48px;
+    text-align: center;
+    font-size: 0.9rem;
+    color: var(--text-muted);
+  }
+
+  .footer-nav {
+    display: flex;
+    justify-content: center;
+    align-items: center;
+    gap: 12px;
+    margin-bottom: 16px;
+  }
+
+  .footer-separator {
+    color: var(--text-muted);
+  }
+
+  .footer a {
+    color: var(--coral-bright);
+    text-decoration: none;
+  }
+
+  .footer a:hover {
+    color: var(--cyan-bright);
+  }
+
+  @media (max-width: 480px) {
+    .container {
+      padding: 24px 16px;
+    }
+
+    .showcase-grid {
+      grid-template-columns: 1fr;
+    }
+
+    .showcase-card {
+      padding: 20px;
+    }
+
+    .cta-buttons {
+      flex-direction: column;
+      align-items: center;
+    }
+
+    .cta-btn {
+      width: 100%;
+      max-width: 280px;
+      justify-content: center;
+    }
+  }
+</style>
